<section class="eco-card"><h1>Run #<?= e((string)$run['id']) ?></h1><p>Status: <span class="eco-badge"><?= e((string)$run['status']) ?></span></p><form method="post" action="/onboarding/runs/<?= e((string)$run['id']) ?>/start"><input type="hidden" name="_csrf" value="<?= e($csrfToken) ?>"><button class="btn" type="submit">Start</button></form><form method="post" action="/onboarding/runs/<?= e((string)$run['id']) ?>/cancel"><input type="hidden" name="_csrf" value="<?= e($csrfToken) ?>"><button class="btn" type="submit">Cancel</button></form></section>
<section class="eco-card"><h3>Steps</h3><table class="eco-table"><tbody><?php foreach($steps as $s): ?><tr><td><?= e((string)$s['name']) ?></td><td><?= e((string)$s['status']) ?></td><td><form method="post" action="/onboarding/run-steps/<?= e((string)$s['id']) ?>/status"><input type="hidden" name="_csrf" value="<?= e($csrfToken) ?>"><select name="status" class="eco-form-control"><?php foreach(['pending','running','completed','failed','skipped'] as $st): ?><option value="<?= e($st) ?>"><?= e($st) ?></option><?php endforeach; ?></select><input class="eco-form-control" name="error_message" placeholder="error opcional"><button class="eco-button" type="submit">Guardar</button></form></td></tr><?php endforeach; ?></tbody></table></section>
<section class="eco-card"><h3>Logs</h3><table class="eco-table"><tbody><?php foreach($logs as $l): ?><tr><td><?= e((string)$l['created_at']) ?></td><td><?= e((string)$l['level']) ?></td><td><?= e((string)$l['message']) ?></td></tr><?php endforeach; ?></tbody></table></section>
